        public void testAggregate()
        {
            var exchange = new ccxt.Exchange(new Dictionary<string, object>() {
                { "id", "sampleexchange" },
            });
            Assert(isGreaterThan(exchange.milliseconds(), 0), "go transpiler workaround");
            Assert("GO_SKIP_START");
            object bids = new List<object>() {new List<object>() {789.1, 111.05}, new List<object>() {789.1, 111.05}, new List<object>() {123.3, 456.2}, new List<object>() {784.2, 111.05}, new List<object>() {789.1, 111.05}};
            object expectedBids = new List<object>() {new List<object>() {123.3, 456.2}, new List<object>() {784.2, 111.05}, new List<object>() {789.1, 333.15}};
            AssertDeepEqual(exchange, null, "aggregate", exchange.aggregate(exchange.sortBy(bids, 0)), expectedBids);
            object asks = new List<object>() {new List<object>() {123.2, 456.2}, new List<object>() {784.2, 222.44}, new List<object>() {789.1, 111.01}};
            object expectedAsks = new List<object>() {new List<object>() {123.2, 456.2}, new List<object>() {784.2, 222.44}, new List<object>() {789.1, 111.01}};
            AssertDeepEqual(exchange, null, "aggregate", exchange.aggregate(exchange.sortBy(asks, 0)), expectedAsks);
            AssertDeepEqual(exchange, null, "aggregate", exchange.aggregate(new List<object>() {}), new List<object>() {});
            // Test 1: Simple aggregation - same price combined
            object result1 = exchange.aggregate(new List<object>() {new List<object>() {100.2, 1.01}, new List<object>() {101.5, 2.01}, new List<object>() {100.2, 0.5}});
            AssertDeepEqual(exchange, null, "testAggregate", result1, new List<object>() {new List<object>() {100.2, 1.51}, new List<object>() {101.5, 2.01}});
            // Test 2: With extra fields (should be ignored)
            object result2 = exchange.aggregate(new List<object>() {new List<object>() {100.2, 1.01, "extra"}, new List<object>() {101.5, 2.01, "data", "more"}});
            AssertDeepEqual(exchange, null, "testAggregate", result2, new List<object>() {new List<object>() {100.2, 1.01}, new List<object>() {101.5, 2.01}});
            // Test 3: Zero volumes should be skipped
            object result3 = exchange.aggregate(new List<object>() {new List<object>() {100.2, 1.01}, new List<object>() {101.5, 0}, new List<object>() {102.4, 2.01}});
            AssertDeepEqual(exchange, null, "testAggregate", result3, new List<object>() {new List<object>() {100.2, 1.01}, new List<object>() {102.4, 2.01}});
            // Test 4: Empty array
            object result4 = exchange.aggregate(new List<object>() {});
            AssertDeepEqual(exchange, null, "testAggregate", result4, new List<object>() {});
            // Test 5: Single entry
            object result5 = exchange.aggregate(new List<object>() {new List<object>() {100.2, 1.01}});
            AssertDeepEqual(exchange, null, "testAggregate", result5, new List<object>() {new List<object>() {100.2, 1.01}});
            // Test 6: Many same prices aggregated
            object result6 = exchange.aggregate(new List<object>() {new List<object>() {100.2, 0.12}, new List<object>() {100.2, 0.2}, new List<object>() {100.2, 0.3}, new List<object>() {100.2, 0.4}});
            AssertDeepEqual(exchange, null, "testAggregate", result6, new List<object>() {new List<object>() {100.2, 1.02}});
            // Test 7: All zero volumes - empty result
            object result7 = exchange.aggregate(new List<object>() {new List<object>() {100.2, 0}, new List<object>() {101.5, 0}, new List<object>() {102.4, 0}});
            AssertDeepEqual(exchange, null, "testAggregate", result7, new List<object>() {});
            // // Test 8: Preserves order of first occurrence
            // const result8 = exchange.aggregate ([ [ 103, 1.0 ], [ 101.5, 1.0 ], [ 102.4, 1.0 ], [ 101.5, 0.5 ] ]);
            // AssertDeepEqual (exchange, undefined, 'testAggregate', result8, [ [ 103, 1.0 ], [ 101.5, 1.5 ], [ 102.4, 1.0 ] ]);
            // Test 9: Decimal prices
            object result9 = exchange.aggregate(new List<object>() {new List<object>() {100.5, 1.04}, new List<object>() {100.5, 2.04}, new List<object>() {101.5, 1.05}});
            AssertDeepEqual(exchange, null, "testAggregate", result9, new List<object>() {new List<object>() {100.5, 3.08}, new List<object>() {101.5, 1.05}});
            // Test 10: Mixed zero and non-zero for same price
            object result10 = exchange.aggregate(new List<object>() {new List<object>() {100.2, 1.04}, new List<object>() {100.2, 0}, new List<object>() {100.2, 2.04}});
            AssertDeepEqual(exchange, null, "testAggregate", result10, new List<object>() {new List<object>() {100.2, 3.08}});
            Assert("GO_SKIP_END");
        }
